function maxJumps(arr, d) {
    const n = arr.length;
    const dp = new Array(n).fill(1);

    function helper(idx) {
        if (dp[idx] > 1) {
            return dp[idx];
        }
        let maximum = 1;

        for (let i = 1; i <= d; i++) {
            if (idx + i < n && arr[idx] <= arr[idx + i]) break;
            if (idx + i < n)
                maximum = Math.max(maximum, 1 + helper(idx + i));

            if (idx - i >= 0 && arr[idx] <= arr[idx - i]) break;
            if (idx - i >= 0)
                maximum = Math.max(maximum, 1 + helper(idx - i));
        }
        dp[idx] = maximum;
        return maximum;
    }

    for (let i = 0; i < n; i++) {
        helper(i);
    }

    return Math.max(...dp);
}
